mapper.select:
SELECT work_order.id, work_order.product_id, product.name as productName, work_order.line_id, line.name as lineName, work_order.quantity, work_order.status, work_order.priority, work_order.planning_time, work_order.creator_id, sys_user.name as creatorName, work_order.remarks, work_order.create_time, work_order.update_time FROM work_order LEFT JOIN product ON work_order.product_id = product.id LEFT JOIN line ON work_order.line_id = line.id LEFT JOIN sys_user ON work_order.creator_id = sys_user.id
AND work_order.id = #{id}
AND work_order.status = #{status}
AND work_order.priority = #{priority}
AND DATE_FORMAT(work_order.create_time, '%Y-%m-%d') = DATE_FORMAT(#{createTime}, '%Y-%m-%d')
ORDER BY create_time DESC

SELECT COUNT(*)
FROM work_process
WHERE order_id = #{orderId}
  AND process_seq = #{processSeq}

mapper.update:
UPDATE work_process





        qualified_quantity = #{qualifiedQuantity},


        bad_quantity = #{badQuantity},


        operator_id = #{operatorId},


        remarks = #{remarks},


        start_time = #{startTime},


        finish_time = #{finishTime},


        update_time = #{updateTime}


WHERE order_id = #{orderId}
AND process_seq = #{processSeq}

mapper.select:
SELECT DATE(wp.create_time) AS date, SUM(wp.qualified_quantity) AS qualified_quantity, SUM(wp.bad_quantity) AS bad_quantity, SUM(wp.qualified_quantity + wp.bad_quantity) AS total_quantity, IF(SUM(wp.qualified_quantity + wp.bad_quantity) > 0, ROUND(SUM(wp.qualified_quantity) * 100.0 / SUM(wp.qualified_quantity + wp.bad_quantity), 2), 0) AS pass_rate FROM work_process wp
AND wp.create_time >= #{startTime}
AND wp.create_time <= #{endTime}
GROUP BY DATE(wp.create_time) ORDER BY date
